// --- HELPER FOR ROBUST FETCHING ---
async function fetchWithFallback<T>(input: RequestInfo, init?: RequestInit, fallbackData?: T): Promise<T> {
  try {
    // Try to fetch from the real backend
    const res = await fetch(input, init);
    if (!res.ok) {
      throw new Error(`Server returned ${res.status} ${res.statusText}`);
    }
    return await res.json();
  } catch (error) {
    console.warn(`API Connection Failed for ${input}. Using fallback data.`, error);
    if (fallbackData !== undefined) {
      return fallbackData;
    }
    throw error;
  }
}

