Service API qui priorise le Backend local, mais garde un fallback pour √©viter les crashs si le serveur est √©teint.

```typescript
import { Listing, Order, User, UserRole, ListingType, OrderStatus, SubscriptionTier } from '../types';

const API_URL = 'http://localhost:3001/api';

// Helper to fetch from backend first, with robust error logging
async function fetchWithFallback<T>(input: RequestInfo, init?: RequestInit, fallbackData?: T): Promise<T> {
  try {
    const res = await fetch(input, init);
    if (!res.ok) {
        // Try to parse error message from JSON
        const errorBody = await res.json().catch(() => ({}));
        throw new Error(errorBody.error || `Server returned ${res.status}`);
    }
    return await res.json();
  } catch (error) {
    console.error(`API Call Failed to ${input}:`, error);
    if (fallbackData !== undefined) {
      console.warn("Using fallback data for demonstration.");
      return fallbackData;
    }
    throw error;
  }
