```typescript
import { Listing, Order, User, UserRole, OrderStatus, SubscriptionTier, Category, SubCategory, CartItem, DashboardStats } from '../types';

const API_URL = 'http://localhost:3001/api';

async function fetchWithFallback<T>(input: RequestInfo, init?: RequestInit, fallbackData?: T): Promise<T> {
  try {
    const res = await fetch(input, init);
    if (!res.ok) throw new Error(res.statusText);
    return await res.json();
  } catch (error) {
    console.warn(`API Fail: ${input}`, error);
    if (fallbackData) return fallbackData;
    throw error;
  }
}

const getHeaders = () => {
  const token = localStorage.getItem('token');
  return {
    'Content-Type': 'application/json',
    ...(token ? { 'Authorization': `Bearer ${token}` } : {})
  };
};

export const api = {
  login: (e:string, p:string) => fetchWithFallback(`${API_URL}/auth/login`, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:e,password:p})}),
  register: (e:string, p:string, u:string) => fetchWithFallback(`${API_URL}/auth/register`, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:e,password:p,username:u})}),
  getCurrentUser: () => fetchWithFallback<User>(`${API_URL}/auth/me`, {headers:getHeaders()}),
  updateSubscription: (d:any) => fetchWithFallback(`${API_URL}/users/subscribe`, {method:'POST',headers:getHeaders(),body:JSON.stringify(d)}),

  getCart: () => fetchWithFallback<CartItem[]>(`${API_URL}/cart`, {headers:getHeaders()}, []),
  addToCart: (lid:string) => fetchWithFallback(`${API_URL}/cart`, {method:'POST',headers:getHeaders(),body:JSON.stringify({listingId:lid})}),
  removeFromCart: (id:string) => fetchWithFallback(`${API_URL}/cart/${id}`, {method:'DELETE',headers:getHeaders()}),
  checkout: () => fetchWithFallback<Order>(`${API_URL}/checkout`, {method:'POST',headers:getHeaders()}),

  getCategories: () => fetchWithFallback<Category[]>(`${API_URL}/categories`, undefined, []),
  createCategory: (d:Partial<Category>) => fetchWithFallback(`${API_URL}/categories`, {method:'POST',headers:getHeaders(),body:JSON.stringify(d)}),
  deleteCategory: (id:string) => fetchWithFallback(`${API_URL}/categories/${id}`, {method:'DELETE',headers:getHeaders()}),
  createSubCategory: (d:Partial<SubCategory>) => fetchWithFallback(`${API_URL}/subcategories`, {method:'POST',headers:getHeaders(),body:JSON.stringify(d)}),
  deleteSubCategory: (id:string) => fetchWithFallback(`${API_URL}/subcategories/${id}`, {method:'DELETE',headers:getHeaders()}),

  getListings: () => fetchWithFallback<Listing[]>(`${API_URL}/listings`, undefined, []),
  createListing: (d:Partial<Listing>) => fetchWithFallback(`${API_URL}/listings`, {method:'POST',headers:getHeaders(),body:JSON.stringify(d)}),

  getMyOrders: () => fetchWithFallback<Order[]>(`${API_URL}/orders/my`, {headers:getHeaders()}, []),
  getAllOrders: () => fetchWithFallback<Order[]>(`${API_URL}/orders/admin`, {headers:getHeaders()}, []),

  // Analytics
  getDashboardStats: () => fetchWithFallback<DashboardStats>(`${API_URL}/admin/stats`, {headers:getHeaders()}),
  getAllUsers: () => fetchWithFallback<User[]>(`${API_URL}/users`, {headers:getHeaders()}, []),
};
```

