import { Listing, Order, User, UserRole, SubscriptionTier, Category, SubCategory, CartItem, DashboardStats } from '../types';
const API_URL = 'http://localhost:3001/api';

async function fetchWithFallback<T>(input: RequestInfo, init?: RequestInit, fallbackData?: T): Promise<T> {
  try {
    const res = await fetch(input, init);
    if (!res.ok) throw new Error(res.statusText);
    return await res.json();
  } catch (error) {
    if (fallbackData) return fallbackData;
    throw error;
  }
}
const getHeaders = () => {
  const token = localStorage.getItem('token');
  return { 'Content-Type': 'application/json', ...(token ? { 'Authorization': `Bearer ${token}` } : {}) };
};

export const api = {
  login: (e:string, p:string) => fetchWithFallback(`${API_URL}/auth/login`, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:e,password:p})}),
  register: (e:string, p:string, u:string) => fetchWithFallback(`${API_URL}/auth/register`, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:e,password:p,username:u})}),
  getCurrentUser: () => fetchWithFallback<User>(`${API_URL}/auth/me`, {headers:getHeaders()}),
  updateSubscription: (d:any) => fetchWithFallback(`${API_URL}/users/subscribe`, {method:'POST',headers:getHeaders(),body:JSON.stringify(d)}),
