import { Listing, Order, User, UserRole, SubscriptionTier, Category, SubCategory, CartItem, DashboardStats } from '../types';
const API_URL = 'http://localhost:3001/api';

async function fetchWithFallback<T>(input: RequestInfo, init?: RequestInit, fallbackData?: T): Promise<T> {
  try {
    const res = await fetch(input, init);
    if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.error || res.statusText);
    }
    return await res.json();
  } catch (error) {
    console.warn(`API Fail: ${input}`, error);
    if (fallbackData !== undefined) return fallbackData;
    throw error;
  }
}
const getHeaders = () => {
  const token = localStorage.getItem('token');
  return { 'Content-Type': 'application/json', ...(token ? { 'Authorization': `Bearer ${token}` } : {}) };
};

export const api = {
  login: (e:string, p:string) => fetchWithFallback(`${API_URL}/auth/login`, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:e,password:p})}),
